#include <bits/stdc++.h>
using namespace std;
int n,a[100005],ans,sum;
map<int,int> p;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        if(a[i])
            sum++;
        else
            sum--;
        if(sum==0)
            ans=max(ans,i);
        else if(p[sum])
            ans=max(ans,i-p[sum]);
        if(!p[sum])
            p[sum]=i;
    }
    printf("%d",ans);
    return 0;
}
